 76→                IQ_CONSISTENCY_OFFSET_VECTOR_ENABLED,
 77→                false
 78→            );
 79→            // register the store
 80→            open = true;
 81→
 82→            stateStoreContext.register(
 83→                root,
 84→                (RecordBatchingStateRestoreCallback) records -> {
 85→                    synchronized (position) {
 86→                        for (final ConsumerRecord<byte[], byte[]> record : records) {
 87→                            put(Bytes.wrap(record.key()), record.value());
 88→                            ChangelogRecordDeserializationHelper.applyChecksAndUpdatePosition(
 89→                                record,
 90→                                consistencyEnabled,
 91→                                position
 92→                            );
 93→                        }
 94→                    }
 95→                }
 96→            );
 97→        }
 98→
