152→    // the unlocked implementation of put method, to avoid multiple lock/unlock cost in `putAll` method
153→    private void putInternal(final Bytes key, final byte[] value) {
154→        synchronized (position) {
155→            if (value == null) {
156→                map.remove(key);
157→            } else {
158→                map.put(key, value);
159→            }
160→
161→            StoreQueryUtils.updatePosition(position, context);
162→        }
163→    }
164→
165→    @Override
166→    public synchronized void putAll(final List<KeyValue<Bytes, byte[]>> entries) {
167→        for (final KeyValue<Bytes, byte[]> entry : entries) {
168→            putInternal(entry.key, entry.value);
169→        }
170→    }
