172→    @Override
173→    public synchronized <PS extends Serializer<P>, P> KeyValueIterator<Bytes, byte[]> prefixScan(final P prefix, final PS prefixKeySerializer) {
174→
175→        final Bytes from = Bytes.wrap(prefixKeySerializer.serialize(null, prefix));
176→        final Bytes to = Bytes.increment(from);
177→
178→        return new InMemoryKeyValueIterator(map.subMap(from, true, to, false).keySet(), true);
