196→    private KeyValueIterator<Bytes, byte[]> range(final Bytes from, final Bytes to, final boolean forward) {
197→        if (from == null && to == null) {
198→            return getKeyValueIterator(map.keySet(), forward);
199→        } else if (from == null) {
200→            return getKeyValueIterator(map.headMap(to, true).keySet(), forward);
201→        } else if (to == null) {
202→            return getKeyValueIterator(map.tailMap(from, true).keySet(), forward);
203→        } else if (from.compareTo(to) > 0) {
204→            LOG.warn("Returning empty iterator for fetch with invalid key range: from > to. " +
205→                    "This may be due to range arguments set in the wrong order, " +
206→                    "or serdes that don't preserve ordering when lexicographically comparing the serialized bytes. " +
207→                    "Note that the built-in numerical serdes do not follow this for negative numbers");
