259→            if (!iteratorOpen) {
260→                throw new IllegalStateException(String.format("Iterator for store %s has already been closed.", name));
261→            }
262→            if (currentKey != null) {
263→                if (map.containsKey(currentKey)) {
264→                    return true;
265→                } else {
266→                    currentKey = null;
267→                    return hasNext();
268→                }
269→            }
270→            if (!iter.hasNext()) {
271→                return false;
272→            }
273→            currentKey = iter.next();
