package org.apache.kafka.streams.state.internals;

import org.apache.kafka.common.header.internals.RecordHeaders;
import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.KeyValue;
import org.apache.kafka.streams.processor.internals.ProcessorRecordContext;
import org.apache.kafka.test.InternalMockProcessorContext;

import java.util.ArrayList;
import java.util.List;

/**
 * Fray test to detect the deadlock in InMemoryKeyValueStore caused by
 * inconsistent lock ordering between put() and the restore callback.
 *
 * put() acquires: this -> position
 * restore callback acquires: position -> this
 *
 * Run with: fray-gradle org.apache.kafka.streams.state.internals.InMemoryKeyValueStoreDeadlockTest -- --iter 1000
 */
public class InMemoryKeyValueStoreDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final InMemoryKeyValueStore store = new InMemoryKeyValueStore("test-store");
        final InternalMockProcessorContext<Void, Void> context = new InternalMockProcessorContext<>();
        context.setRecordContext(new ProcessorRecordContext(0, 0, 0, "topic", new RecordHeaders()));
        store.init(context, store);

        // Prepare restore entries
        final List<KeyValue<byte[], byte[]>> restoreEntries = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            restoreEntries.add(new KeyValue<>(
                ("restore-key-" + i).getBytes(),
                ("restore-val-" + i).getBytes()
            ));
        }

        // Thread 1: normal put path (acquires this -> position)
        final Thread putThread = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                store.put(Bytes.wrap(("key-" + i).getBytes()), ("value-" + i).getBytes());
            }
        });

        // Thread 2: restore callback path (previously acquired position -> this)
        final Thread restoreThread = new Thread(() -> {
            context.restore(store.name(), restoreEntries);
        });

        putThread.start();
        restoreThread.start();

        putThread.join();
        restoreThread.join();
    }
}

